SELECT category_id, channel_id, MAX(response_rate) AS highest_response_rate
FROM message_analytics
GROUP BY category_id, channel_id;

SELECT COUNT(message_id) AS num_unresolved_messages
FROM message_assignments
WHERE status != 'completed';

SELECT activity_type, activity_time
FROM message_logs
WHERE responder_id = 1;

SELECT users.user_id, users.name 
FROM users 
WHERE users.last_login > (
    SELECT MIN(created_at) 
    FROM messages
);

SELECT message_id, COUNT(*) AS Total_Responses
FROM response_messages
GROUP BY message_id;

SELECT messages.message_id, messages.message_text, message_templates.template_name
FROM messages
INNER JOIN message_templates ON messages.category_id = message_templates.category_id;

SELECT message_id 
FROM message_analytics 
WHERE average_response_time < 30;
